spec.setup_code:
return {
  draw: function(ctx, W, H, t, dt) {
    // Background
    ctx.fillStyle = '#111827';
    ctx.fillRect(0, 0, W, H);

    var duration = 12000;
    var progress = (t % duration) / duration;

    var stage = 1;
    if (progress >= 0.33 && progress < 0.66) stage = 2;
    else if (progress >= 0.66) stage = 3;

    var midY = H / 2 - 20;
    var midX = W / 2;
    var step = (W - 80) / 8; // spacing for -4 to 4
    var startX = 40;

    // Draw axis line
    ctx.strokeStyle = '#4B5563';
    ctx.lineWidth = 2;
    ctx.beginPath();
    ctx.moveTo(20, midY);
    ctx.lineTo(W - 20, midY);
    ctx.stroke();

    // Draw tick marks and labels for -4 to 4
    ctx.textAlign = 'center';
    ctx.textBaseline = 'top';
    ctx.font = '12px monospace';
    for (var i = -4; i <= 4; i++) {
      var tx = midX + i * step;
      ctx.strokeStyle = '#4B5563';
      ctx.lineWidth = 1.5;
      ctx.beginPath();
      ctx.moveTo(tx, midY - 4);
      ctx.lineTo(tx, midY + 4);
      ctx.stroke();

      // Highlight 0, -3, 3 depending on stage
      if (i === 0) {
        ctx.fillStyle = '#10B981';
      } else if (stage === 1 && i === 3) {
        ctx.fillStyle = '#3B82F6';
      } else if (stage === 2 && i === -3) {
        ctx.fillStyle = '#EF4444';
      } else if (stage === 3 && (i === -3 || i === 3)) {
        ctx.fillStyle = '#F59E0B';
      } else {
        ctx.fillStyle = '#9CA3AF';
      }
      ctx.fillText(i.toString(), tx, midY + 8);
    }

    // Draw arrows showing distance
    if (stage === 1) {
      // Distance to +3
      var animProgress = (progress) / 0.33;
      var currentX = midX + 3 * step * animProgress;

      ctx.strokeStyle = '#3B82F6';
      ctx.lineWidth = 3;
      ctx.beginPath();
      ctx.moveTo(midX, midY - 15);
      ctx.lineTo(currentX, midY - 15);
      ctx.stroke();

      // Arrowhead
      ctx.fillStyle = '#3B82F6';
      ctx.beginPath();
      ctx.moveTo(currentX, midY - 15);
      ctx.lineTo(currentX - 6, midY - 19);
      ctx.lineTo(currentX - 6, midY - 11);
      ctx.fill();
    } else if (stage === 2) {
      // Distance to -3
      var animProgress = (progress - 0.33) / 0.33;
      var currentX = midX - 3 * step * animProgress;

      ctx.strokeStyle = '#EF4444';
      ctx.lineWidth = 3;
      ctx.beginPath();
      ctx.moveTo(midX, midY - 15);
      ctx.lineTo(currentX, midY - 15);
      ctx.stroke();

      // Arrowhead
      ctx.fillStyle = '#EF4444';
      ctx.beginPath();
      ctx.moveTo(currentX, midY - 15);
      ctx.lineTo(currentX + 6, midY - 19);
      ctx.lineTo(currentX + 6, midY - 11);
      ctx.fill();
    } else {
      // Both distances highlighted
      ctx.strokeStyle = '#3B82F6';
      ctx.lineWidth = 3;
      ctx.beginPath();
      ctx.moveTo(midX, midY - 15);
      ctx.lineTo(midX + 3 * step, midY - 15);
      ctx.stroke();
      ctx.fillStyle = '#3B82F6';
      ctx.beginPath();
      ctx.moveTo(midX + 3 * step, midY - 15);
      ctx.lineTo(midX + 3 * step - 6, midY - 19);
      ctx.lineTo(midX + 3 * step - 6, midY - 11);
      ctx.fill();

      ctx.strokeStyle = '#EF4444';
      ctx.beginPath();
      ctx.moveTo(midX, midY - 25);
      ctx.lineTo(midX - 3 * step, midY - 25);
      ctx.stroke();
      ctx.fillStyle = '#EF4444';
      ctx.beginPath();
      ctx.moveTo(midX - 3 * step, midY - 25);
      ctx.lineTo(midX - 3 * step + 6, midY - 29);
      ctx.lineTo(midX - 3 * step + 6, midY - 21);
      ctx.fill();
    }

    // Bottom text explanations
    ctx.textAlign = 'center';
    ctx.textBaseline = 'middle';
    ctx.font = 'bold 15px -apple-system, sans-serif';
    ctx.fillStyle = '#F3F4F6';

    if (stage === 1) {
      ctx.fillText('|3| = 3', W / 2, H - 42);
      ctx.font = '11px -apple-system, sans-serif';
      ctx.fillStyle = '#9CA3AF';
      ctx.fillText('The number 3 is exactly 3 units to the right of zero.', W / 2, H - 22);
    } else if (stage === 2) {
      ctx.fillStyle = '#F87171';
      ctx.fillText('|-3| = 3', W / 2, H - 42);
      ctx.font = '11px -apple-system, sans-serif';
      ctx.fillStyle = '#9CA3AF';
      ctx.fillText('The number -3 is also exactly 3 units to the left of zero.', W / 2, H - 22);
    } else {
      ctx.fillStyle = '#FBBF24';
      ctx.fillText('Absolute Value strips away direction!', W / 2, H - 42);
      ctx.font = '11px -apple-system, sans-serif';
      ctx.fillStyle = '#9CA3AF';
      ctx.fillText('Distance is always a positive magnitude. Both |3| and |-3| equal 3.', W / 2, H - 22);
    }
  }
};
